        "question": "What is the correct file extension for Python files?",
        "options": ["*.py", "*.pt", "*.python", "*.p"],
        "correctAnswer": 0,
        "explanation": "Python files use the .py extension."
      },
      {
        "question": "Which of the following is a valid variable name in Python?",
        "options": ["1st_variable", "variable-name", "variable_name", "variable name"],
        "correctAnswer": 2,
        "explanation": "Variable names must start with a letter or underscore and can contain letters, numbers, and underscores."
      },
      {
        "question": "What is the output of print(2 + 3)?",
        "options": ["5", "23", "Error", "None"],
        "correctAnswer": 0,
        "explanation": "The output of print(2 + 3) is 5."
      },
      {
        "question": "Which keyword is used to define a function in Python?",
        "options": ["function", "def", "define", "fun"],
        "correctAnswer": 1,
        "explanation": "The 'def' keyword is used to define a function in Python."
      }
    ]
  }
